-- ── Summary ───────────────────────────────────────────────────
SELECT
  CONCAT(o.code,' → ',d.code) AS route,
  CONCAT(o.city,' → ',d.city) AS cities,
  COUNT(*) AS flights,
  CONCAT('₹',FORMAT(MIN(f.economy_price),0)) AS economy_from
FROM flights f
JOIN airports o ON f.origin_id = o.id
JOIN airports d ON f.destination_id = d.id
WHERE f.flight_number LIKE 'TXI%'
  AND f.departure_time > NOW()
  AND f.is_active = 1
GROUP BY f.origin_id, f.destination_id
ORDER BY flights DESC;
